 1→import { getTodaysPromptService, getPromptResponsesService } from "../services/promptService.js";
 2→
 3→export const getTodaysPromptController = async (req, res) => {
 4→    try {
 5→        const prompt = await getTodaysPromptService();
 6→        if (!prompt) {
 7→            return res.status(404).json({ error: 'no prompt available' });
 8→        }
 9→        return res.status(200).json(prompt);
10→    } catch (err) {
11→        console.error('error in getTodaysPromptController:', err);
12→        return res.status(500).json({ error: 'failed to get prompt' });
13→    }
14→};
15→
16→export const getPromptResponsesController = async (req, res) => {
17→    try {
18→        const { promptId } = req.params;
19→        if (!promptId) {
20→            return res.status(400).json({ error: 'promptId is required' });
21→        }
22→        const result = await getPromptResponsesService(parseInt(promptId, 10));
23→        return res.status(200).json(result);
24→    } catch (err) {
25→        console.error('error in getPromptResponsesController:', err);
26→        return res.status(500).json({ error: 'failed to get prompt responses' });
27→    }
28→};
